/// Calculates the total file size for a batch of downloads using checked arithmetic
/// to prevent overflow.
///
/// # Arguments
/// * `file_sizes` - A vector of individual file sizes in bytes
///
/// # Returns
/// * `Ok(u64)` - The total size in bytes
/// * `Err(BatchSizeError)` - If the input is invalid or overflow occurs
pub fn calculate_total_batch_size(file_sizes: &[u64]) -> Result<u64, BatchSizeError> {
    if file_sizes.is_empty() {
        return Err(BatchSizeError::EmptyFileList);
    }

    // Validate individual file sizes
    for (index, &size) in file_sizes.iter().enumerate() {
        if size == 0 {
            return Err(BatchSizeError::ZeroSizeFile { index });
        }
    }

    // Use checked_add to safely sum all file sizes without overflow
    let mut total: u64 = 0;
    for &size in file_sizes {
        total = total.checked_add(size).ok_or(BatchSizeError::Overflow)?;
    }

    Ok(total)
}

/// Calculates total batch size and verifies it fits within available disk space.
///
/// # Arguments
/// * `file_sizes` - A vector of individual file sizes in bytes
/// * `available_disk_space` - Available disk space in bytes
